### 1.1 初始化

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;
signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 默认构造（全 0）
    bitset<8> b1;

    // 整数构造
    bitset<8> b2(42);  // 00101010

    // 字符串构造
    bitset<8> b3("10101010");

    // 拷贝构造
    bitset<8> b4(b2);

    // 移动构造
    bitset<8> b5(move(b4));

    return 0;
}
```

### 1.2 基本操作

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;
signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    bitset<8> b;

    // 设置位
    b.set(0);     // 第0位设为1
    b.set(2, 1);  // 第2位设为1
    b.set();      // 所有位设为1

    // 清除位
    b.reset(0);   // 第0位设为0
    b.reset();    // 所有位设为0

    // 翻转位
    b.flip(1);    // 翻转第1位
    b.flip();     // 翻转所有位

    // 测试位
    bool is_set = b.test(0);
    bool any_set = b.any();    // 是否有位为1
    bool all_set = b.all();    // 是否所有位为1
    bool none_set = b.none();  // 是否所有位为0

    // 计数
    int count = b.count();  // 置位的位数

    // 大小
    size_t size = b.size();  // 总位数

    // 转换
    unsigned long ul = b.to_ulong();
    unsigned long long ull = b.to_ullong();
    string s = b.to_string();

    return 0;
}
```

