## 二、位运算

### 2.1 基本位运算

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;
signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    bitset<4> a("1010");  // 10
    bitset<4> b("1100");  // 12

    // 按位与
    bitset<4> c = a & b;  // 1000 (8)

    // 按位或
    bitset<4> d = a | b;  // 1110 (14)

    // 按位异或
    bitset<4> e = a ^ b;  // 0110 (6)

    // 按位取反
    bitset<4> f = ~a;     // 0101 (5)

    // 左移
    bitset<4> g = a << 1;  // 0100 (4)

    // 右移
    bitset<4> h = a >> 1;  // 0101 (5)

    cout << "a: " << a << endl;
    cout << "b: " << b << endl;
    cout << "a & b: " << c << endl;
    cout << "a | b: " << d << endl;
    cout << "a ^ b: " << e << endl;
    cout << "~a: " << f << endl;
    cout << "a << 1: " << g << endl;
    cout << "a >> 1: " << h << endl;

    return 0;
}
```

### 2.2 复合赋值运算

```cpp
bitset<8> a("10101010");
bitset<8> b("11001100");

// 复合赋值
a &= b;  // 等价于 a = a & b
a |= b;  // 等价于 a = a | b
a ^= b;  // 等价于 a = a ^ b
a <<= 2; // 等价于 a = a << 2
a >>= 2; // 等价于 a = a >> 2
```

