### 3.3 快速统计

```cpp
// 统计二进制中 1 的个数
int count_ones(int x)
{
    bitset<32> bits(x);
    return bits.count();
}

// 检查是否是 2 的幂
bool is_power_of_two(int x)
{
    if (x == 0)
    {
        return false;
    }
    bitset<32> bits(x);
    return bits.count() == 1;
}

// 查找最低位的 1
int find_lowest_set_bit(int x)
{
    bitset<32> bits(x);
    return bits._Find_first();
}

// 查找最高位的 1
int find_highest_set_bit(int x)
{
    bitset<32> bits(x);
    int pos = -1;
    for (int i = 31; i >= 0; i--)
    {
        if (bits.test(i))
        {
            pos = i;
            break;
        }
    }
    return pos;
}
```

### 3.4 动态规划优化

```cpp
// 旅行商问题 (TSP) 状态压缩 DP
int tsp(const vector<vector<int>>& dist)
{
    int n = dist.size();
    int full_mask = (1 << n) - 1;
    vector<vector<int>> dp(1 << n, vector<int>(n, INT_MAX));

    // 初始化：从各个城市出发
    for (int i = 0; i < n; i++)
    {
        dp[1 << i][i] = 0;
    }

    // 状态转移
    for (int mask = 0; mask < (1 << n); mask++)
    {
        for (int u = 0; u < n; u++)
        {
            if (!(mask & (1 << u)) || dp[mask][u] == INT_MAX)
            {
                continue;
            }
            for (int v = 0; v < n; v++)
            {
                if (!(mask & (1 << v)) && dist[u][v] != INT_MAX)
                {
                    int new_mask = mask | (1 << v);
                    if (dp[new_mask][v] > dp[mask][u] + dist[u][v])
                    {
                        dp[new_mask][v] = dp[mask][u] + dist[u][v];
                    }
                }
            }
        }
    }

    // 找最小路径
    int result = INT_MAX;
    for (int i = 0; i < n; i++)
    {
        if (dp[full_mask][i] != INT_MAX)
        {
            result = min(result, dp[full_mask][i] + dist[i][0]);
        }
    }

    return result;
}
```

### 3.5 位图

```cpp
// 位图实现
class BitMap
{
private:
    bitset<1000000> bits;
public:
    void set(int x)
    {
        bits.set(x);
    }

    void clear(int x)
    {
        bits.reset(x);
    }

    bool test(int x)
    {
        return bits.test(x);
    }

    int count()
    {
        return bits.count();
    }
};

// 用于快速去重和存在性检查
void deduplicate(vector<int>& nums)
{
    bitset<1000000> seen;
    vector<int> result;

    for (int x : nums)
    {
        if (!seen.test(x))
        {
            seen.set(x);
            result.push_back(x);
        }
    }

    nums.swap(result);
}
```

