### 4.2 位掩码与枚举

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;

// C++11 强类型枚举
enum class Direction : int
{
    UP = 1 << 0,
    DOWN = 1 << 1,
    LEFT = 1 << 2,
    RIGHT = 1 << 3
};

// 重载位运算符
Direction operator|(Direction a, Direction b)
{
    return static_cast<Direction>(static_cast<int>(a) | static_cast<int>(b));
}

Direction operator&(Direction a, Direction b)
{
    return static_cast<Direction>(static_cast<int>(a) & static_cast<int>(b));
}

