    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    Direction dir = Direction::UP | Direction::RIGHT;
    bool can_go_up = (dir & Direction::UP) != static_cast<Direction>(0);
    cout << "Can go up: " << can_go_up << endl;

    return 0;
}
