### 3.4 二叉树遍历

```cpp
// 二叉树结构
struct TreeNode
{
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

// 前序遍历（非递归）
vector<int> preorder_traversal(TreeNode* root)
{
    vector<int> result;
    if (!root)
    {
        return result;
    }

    stack<TreeNode*> stk;
    stk.push(root);

    while (!stk.empty())
    {
        TreeNode* node = stk.top();
        stk.pop();
        result.push_back(node->val);

        // 先压右子树，再压左子树
        if (node->right)
        {
            stk.push(node->right);
        }
        if (node->left)
        {
            stk.push(node->left);
        }
    }

    return result;
}

// 中序遍历（非递归）
vector<int> inorder_traversal(TreeNode* root)
{
    vector<int> result;
    stack<TreeNode*> stk;
    TreeNode* current = root;

    while (current || !stk.empty())
    {
        while (current)
        {
            stk.push(current);
            current = current->left;
        }

        current = stk.top();
        stk.pop();
        result.push_back(current->val);
        current = current->right;
    }

    return result;
}

// 后序遍历（非递归）
vector<int> postorder_traversal(TreeNode* root)
{
    vector<int> result;
    if (!root)
    {
        return result;
    }

    stack<TreeNode*> stk1, stk2;
    stk1.push(root);

    while (!stk1.empty())
    {
        TreeNode* node = stk1.top();
        stk1.pop();
        stk2.push(node);

        if (node->left)
        {
            stk1.push(node->left);
        }
        if (node->right)
        {
            stk1.push(node->right);
        }
    }

    while (!stk2.empty())
    {
        result.push_back(stk2.top()->val);
        stk2.pop();
    }

    return result;
}
```

