### 8.2 邻接表存图

```cpp
int n, m;  // n个点，m条边
cin >> n >> m;

vector<vector<pair<int, int>>> g(n);  // g[u] = {(v, w), ...}

for (int i = 0; i < m; i++)
{
    int u, v, w;
    cin >> u >> v >> w;
    u--; v--;  // 转0-indexed
    g[u].emplace_back(v, w);
    // 无向图：g[v].emplace_back(u, w);
}

// 遍历u的邻接点 (C++11)
for (auto& p : g[u])
{
    int to = p.first;
    int w = p.second;
    // to是邻接点，w是边权
}
```

### 8.3 动态规划中的滚动数组

```cpp
// 优化前：二维DP
vector<vector<int>> dp(n, vector<int>(m, 0));

// 优化后：滚动数组（只保留两行）
vector<int> dp(m), newdp(m);
for (int i = 0; i < n; i++)
{
    for (int j = 0; j < m; j++)
    {
        newdp[j] = ...;  // 计算
    }
    swap(dp, newdp);  // C++11 swap
}
```

### 8.4 离散化

```cpp
vector<int> a = {100, 50, 200, 50, 100, 300};
vector<int> vals = a;  // 拷贝

// C++11 离散化
sort(all(vals));
vals.erase(unique(all(vals)), vals.end());

// 映射
for (auto& x : a)
{
    x = lower_bound(all(vals), x) - vals.begin();
}
// a 变为 {2, 0, 3, 0, 2, 4}
```

